Java1.8之后扩容机制
底层结构是
数组+链表 / 红黑树
当
链表长度
大于等于8时，判断
HashMap的size
是否大于等于64，如果小于64，则进行扩容，否则将
链表转换为红黑树
。
当
红黑树节点数量
小于等于6时，会将
红黑树转换为链表
。
遍历原数组的每个桶，转移元素到新数组中，分三种情况处理：
桶中没有元素：跳过
桶中只有一个元素：直接放入。
桶中是链表或者红黑树：
链表：求新桶位置并放入
红黑树：调用split()方法将红黑树拆成两个链表，然后求新桶位置并放入
在扩容时，不需要计算元素的hash值，用
原先位置key的hash值
与
旧数组的长度
进行“
与
”操作，如果结果是0，则新位置就是原位置，否则新位置就是原位置+旧数组长度。
使用
尾插法
将元素插入新数组中。
final Node<K,V>[] resize() {
        //变量初始化，获取旧数组长度、旧阈值
        Node<K,V>[] oldTab = table;
        int oldCap = (oldTab == null) ? 0 : oldTab.length;
        int oldThr = threshold;
        int newCap, newThr = 0;
        //当原数组已经初始化
        if (oldCap > 0) {
            // 原容量已经达到最大值
            if (oldCap >= MAXIMUM_CAPACITY) {
                threshold = Integer.MAX_VALUE;
                return oldTab;
            }
            // 原容量翻倍后没有达到最大值，正常扩容
            else if ((newCap = oldCap << 1) < MAXIMUM_CAPACITY &&
                     oldCap >= DEFAULT_INITIAL_CAPACITY)
                newThr = oldThr << 1; // 阈值翻倍左移一位
        }
        // 原数组未初始化，但是已经设置阈值
        else if (oldThr > 0)
            newCap = oldThr;
        // 原数组未初始化，没有设置阈值
        else {
            newCap = DEFAULT_INITIAL_CAPACITY;
            newThr = (int)(DEFAULT_LOAD_FACTOR * DEFAULT_INITIAL_CAPACITY);
        }
        // 补全新阈值
        if (newThr == 0) {
            float ft = (float)newCap * loadFactor;
            newThr = (newCap < MAXIMUM_CAPACITY && ft < (float)MAXIMUM_CAPACITY ?
                      (int)ft : Integer.MAX_VALUE);
        }
        // 更新全局阈值
        threshold = newThr;
        // 创建数组并迁移元素
        @SuppressWarnings({"rawtypes","unchecked"})
        Node<K,V>[] newTab = (Node<K,V>[])new Node[newCap];
        table = newTab;
        // 原数组非空
        if (oldTab != null) {
            for (int j = 0; j < oldCap; ++j) {
                Node<K,V> e;
                if ((e = oldTab[j]) != null) {
                    oldTab[j] = null;
                    // 桶中只有一个元素
                    if (e.next == null)
                        newTab[e.hash & (newCap - 1)] = e;
                    // 桶里是红黑树
                    else if (e instanceof TreeNode)
                        ((TreeNode<K,V>)e).split(this, newTab, j, oldCap);
                    // 桶里是链表
                    else {
                        Node<K,V> loHead = null, loTail = null;
                        Node<K,V> hiHead = null, hiTail = null;
                        Node<K,V> next;
                        do {
                            next = e.next;
                            if ((e.hash & oldCap) == 0) {
                                if (loTail == null)
                                    loHead = e;
                                else
                                    loTail.next = e;
                                loTail = e;
                            }
                            else {
                                if (hiTail == null)
                                    hiHead = e;
                                else
                                    hiTail.next = e;
                                hiTail = e;
                            }
                        } while ((e = next) != null);
                        if (loTail != null) {
                            loTail.next = null;
                            newTab[j] = loHead;
                        }
                        if (hiTail != null) {
                            hiTail.next = null;
                            newTab[j + oldCap] = hiHead;
                        }
                    }
                }
            }
        }
        return newTab;
    }
